import java.util.Map;
import java.util.HashMap;
import java.util.Set;
import java.util.HashSet;
import java.util.List;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.regex.Pattern;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        Map<String, Integer> businessOrder = new HashMap<>();
        businessOrder.put("electronics", 0);
        businessOrder.put("grocery", 1);
        businessOrder.put("pharmacy", 2);
        businessOrder.put("restaurant", 3);

        Set<String> validBusiness = new HashSet<>(Arrays.asList("electronics", "grocery", "pharmacy", "restaurant"));

        List<String[]> validCoupons = new ArrayList<>();

        for (int i = 0; i < code.length; i++) {
            if (!code[i].isEmpty() && Pattern.matches("^[a-zA-Z0-9_]+$", code[i]) && validBusiness.contains(businessLine[i]) && isActive[i]) {
                validCoupons.add(new String[]{businessLine[i], code[i]});
            }
        }

        validCoupons.sort((a, b) -> {
            int orderA = businessOrder.get(a[0]);
            int orderB = businessOrder.get(b[0]);
            if (orderA != orderB) {
                return Integer.compare(orderA, orderB);
            }
            return a[1].compareTo(b[1]);
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[1];
        }

        return result;
    }
}
